<template>
  <div class="fire-calculator" ref="calculatorContainer">
    <div class="header-section">
      <h2>FIRE计算器</h2>
      <div class="header-buttons" v-if="!exporting">
        <van-button type="primary" size="small" @click="addNewPlan" class="add-plan-btn">
          + 新增计划
        </van-button>
        <van-button 
          type="default" 
          size="small" 
          icon="replay" 
          @click="copyCurrentPlan"
          v-if="activePlanId"
        >
          复制
        </van-button>
        <van-button 
          type="warning" 
          size="small" 
          icon="delete" 
          @click="confirmClearCache"
        >
          清除缓存
        </van-button>
      </div>
    </div>
    
    <div class="tabs-container" v-if="plans.length > 0">
      <div class="custom-tabs">
        <div 
          v-for="plan in plans" 
          :key="plan.id"
          :class="['custom-tab', { active: activePlanId === plan.id }]"
          @click="onPlanChange(plan.id)"
        >
          {{ plan.name }}
        </div>
      </div>
    </div>
    
    <div class="plan-actions" v-if="activePlanId">
      <van-button type="default" size="small" @click="openEditPlanDialog(currentPlan)">
        <van-icon name="edit" />
        修改名称
      </van-button>
      <van-button 
        v-if="plans.length > 1"
        type="default" 
        size="small" 
        icon="sort" 
        @click="openSortDialog"
      >
        排序
      </van-button>
      <van-button 
        v-if="plans.length > 1" 
        type="danger" 
        size="small" 
        @click="confirmDeletePlan(activePlanId)"
      >
        <van-icon name="delete-o" />
        删除
      </van-button>
      <van-button type="primary" size="small" @click="exportAsImage" :loading="exporting">
        <van-icon name="photo-o" />
        导出图片
      </van-button>
    </div>
    
    <van-dialog
      v-model="showAddPlanDialog"
      title="新增计划"
      show-cancel-button
      :before-close="beforeAddPlanClose"
    >
      <van-field
        v-model="newPlanName"
        placeholder="请输入计划名称"
        label="计划名称"
        class="plan-name-input"
      />
    </van-dialog>
    
    <van-dialog
      v-model="showEditPlanDialog"
      title="修改计划名称"
      show-cancel-button
      :before-close="beforeEditPlanClose"
    >
      <van-field
        v-model="editPlanName"
        placeholder="请输入计划名称"
        label="计划名称"
        class="plan-name-input"
      />
    </van-dialog>
    
    <van-dialog
      v-model="showSortDialog"
      title="排序计划"
      show-cancel-button
      show-confirm-button
      confirm-button-text="确认"
      cancel-button-text="取消"
      @confirm="confirmSort"
      @cancel="cancelSort"
      :close-on-click-overlay="false"
    >
      <div class="sort-dialog-content">
        <draggable 
          v-model="tempPlans" 
          handle=".drag-handle"
          :animation="200"
          ghost-class="ghost-item"
        >
          <div 
            v-for="(plan, index) in tempPlans" 
            :key="plan.id" 
            class="sort-item"
          >
            <van-icon name="bars" class="drag-handle" />
            <span class="sort-index">{{ index + 1 }}</span>
            <span class="sort-name">{{ plan.name }}</span>
          </div>
        </draggable>
      </div>
    </van-dialog>
    
    <van-form @submit="calculate">
      <van-field
        v-model="formData.startAge"
        name="startAge"
        label="开始年龄"
        placeholder="请输入开始年龄"
        type="number"
        :rules="[{ required: true, message: '请输入开始年龄' }]"
      />
      
      <van-field
        v-model="formData.endAge"
        name="endAge"
        label="结束年龄"
        placeholder="请输入结束年龄"
        type="number"
        :rules="[{ required: true, message: '请输入结束年龄' }]"
      />
      
      <van-field
        v-model="formData.initialAssets"
        name="initialAssets"
        label="总资产"
        placeholder="请输入总资产"
        type="number"
        :rules="[{ required: true, message: '请输入总资产' }]"
      />
      
      <van-field
        v-model="formData.annualReturn"
        name="annualReturn"
        label="年收益率"
        placeholder="请输入年收益率"
        type="number"
        :rules="[{ required: true, message: '请输入年收益率' }]"
      >
        <template #button>%
        </template>
      </van-field>
      
      <!-- 支出项 -->
      <div class="expense-section">
        <h3 class="section-title">支出项</h3>
        <div v-for="(expense, index) in expenseItems" :key="index" class="expense-item">
          <van-field
            v-model="expense.name"
            :name="`expense-name-${index}`"
            label="名称"
            placeholder="请输入支出名称"
            :rules="[{ required: true, message: '请输入支出名称' }]"
            class="expense-name-field"
          />
          <div class="expense-amount-unit">
            <div class="amount-with-unit">
              <van-field
                v-model="expense.amount"
                :name="`expense-amount-${index}`"
                label="金额"
                placeholder="请输入金额"
                type="number"
                :rules="[{ required: true, message: '请输入金额' }]"
                class="expense-amount-field"
                :error-message-align="'left'"
              />
              <div class="unit-selector">
                <van-button 
                  :type="expense.unit === 'yearly' ? 'primary' : 'default'" 
                  size="small" 
                  @click="expense.unit = 'yearly'"
                  class="unit-button"
                >
                  每年
                </van-button>
                <van-button 
                  :type="expense.unit === 'monthly' ? 'primary' : 'default'" 
                  size="small" 
                  @click="expense.unit = 'monthly'"
                  class="unit-button"
                >
                  每月
                </van-button>
              </div>
            </div>
          </div>
          <van-field
            v-if="!expense.untilEndAge"
            v-model="expense.duration"
            :name="`expense-duration-${index}`"
            label="持续时间(年)"
            placeholder="请输入持续时间"
            type="number"
            :rules="[{ required: true, message: '请输入持续时间' }]"
          />
          <van-checkbox v-model="expense.untilEndAge" shape="square" class="until-end-age-checkbox">
            持续到结束年龄
          </van-checkbox>
          <div class="delete-button-container">
            <van-button type="danger" size="small" @click="removeExpenseItem(index)">删除</van-button>
          </div>
        </div>
        <van-button type="default" @click="addExpenseItem" block>添加支出项</van-button>
        <div class="total-expense">
          <span class="total-label">总年支出：</span>
          <span class="total-value">{{ totalYearlyExpense.toLocaleString() }}</span>
        </div>
      </div>
      
      <!-- 收入项 -->
      <div class="income-section">
        <h3 class="section-title">收入项</h3>
        <div v-for="(income, index) in incomeItems" :key="index" class="income-item">
          <van-field
            v-model="income.name"
            :name="`income-name-${index}`"
            label="名称"
            placeholder="请输入收入名称"
            :rules="[{ required: true, message: '请输入收入名称' }]"
            class="income-name-field"
          />
          <div class="income-amount-unit">
            <div class="amount-with-unit">
              <van-field
                v-model="income.amount"
                :name="`income-amount-${index}`"
                label="金额"
                placeholder="请输入金额"
                type="number"
                :rules="[{ required: true, message: '请输入金额' }]"
                class="income-amount-field"
                :error-message-align="'left'"
              />
              <div class="unit-selector">
                <van-button 
                  :type="income.unit === 'yearly' ? 'primary' : 'default'" 
                  size="small" 
                  @click="income.unit = 'yearly'"
                  class="unit-button"
                >
                  每年
                </van-button>
                <van-button 
                  :type="income.unit === 'monthly' ? 'primary' : 'default'" 
                  size="small" 
                  @click="income.unit = 'monthly'"
                  class="unit-button"
                >
                  每月
                </van-button>
              </div>
            </div>
          </div>
          <van-field
            v-if="!income.untilEndAge"
            v-model="income.duration"
            :name="`income-duration-${index}`"
            label="持续时间(年)"
            placeholder="请输入持续时间"
            type="number"
            :rules="[{ required: true, message: '请输入持续时间' }]"
          />
          <van-checkbox v-model="income.untilEndAge" shape="square" class="until-end-age-checkbox">
            持续到结束年龄
          </van-checkbox>
          <div class="delete-button-container">
            <van-button type="danger" size="small" @click="removeIncomeItem(index)">删除</van-button>
          </div>
        </div>
        <van-button type="default" @click="addIncomeItem" block>添加收入项</van-button>
        <div class="total-income">
          <span class="total-label">总收入：</span>
          <span class="total-value">{{ totalYearlyIncome.toLocaleString() }}</span>
        </div>
      </div>
      
      <van-button type="primary" native-type="submit" block ref="calculateButton">计算</van-button>
    </van-form>
    
    <van-button 
      type="primary" 
      round 
      icon="arrow-down" 
      class="scroll-to-calc-btn"
      @click="scrollToCalculate"
      v-if="!exporting"
    >
      计算按钮
    </van-button>
    
    <van-button 
      type="primary" 
      round 
      icon="arrow-up" 
      class="scroll-to-top-btn"
      @click="scrollToTop"
      v-if="!exporting"
    >
      回到顶部
    </van-button>
    
    <div v-if="result.length > 0" class="result">
      <h3>计算结果</h3>
      <div class="final-result">
        <p v-if="isFinancialFree" class="success">🎉 恭喜！您在 {{ formData.endAge }} 岁时能够实现财务自由。</p>
        <p v-else class="error">⚠️ 很遗憾，您在 {{ formData.endAge }} 岁时无法实现财务自由。</p>
      </div>
      <div class="result-container">
        <div class="table-header">
          <div class="table-cell sortable" @click="sortByAge">
            年龄
            <span class="sort-icon">{{ sortOrder === 'asc' ? '↑' : '↓' }}</span>
          </div>
          <div class="table-cell">资产情况</div>
          <div class="table-cell">年支出</div>
          <div class="table-cell">年收益</div>
        </div>
        <div class="table-body">
          <div v-for="(item, index) in sortedResult" :key="index" class="table-row">
            <div class="table-cell">{{ item.age }}</div>
            <div class="table-cell">{{ Math.floor(item.assets).toLocaleString() }}</div>
            <div class="table-cell">{{ item.yearlyExpense.toLocaleString() }}</div>
            <div class="table-cell">{{ Math.floor(item.annualReturnAmount).toLocaleString() }}</div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script lang="ts">
import { Component, Vue } from 'vue-property-decorator';
import html2canvas from 'html2canvas';
import draggable from 'vuedraggable';
import defaultFireData from '../assets/fire-data.json';

interface FormData {
  initialAssets: number;
  startAge: number;
  endAge: number;
  annualReturn: number;
}

interface ExpenseItem {
  name: string;
  amount: number;
  unit: 'monthly' | 'yearly';
  duration: number;
  untilEndAge: boolean;
}

interface IncomeItem {
  name: string;
  amount: number;
  unit: 'monthly' | 'yearly';
  duration: number;
  untilEndAge: boolean;
}

interface ResultItem {
  year: number;
  age: number;
  assets: number;
  yearlyExpense: number;
  annualReturn: number;
  annualReturnAmount: number;
}

interface FirePlan {
  id: string;
  name: string;
  formData: FormData;
  expenseItems: ExpenseItem[];
  incomeItems: IncomeItem[];
  result: ResultItem[];
  createdAt: number;
}

const STORAGE_KEY = 'fire_calculator_plans';

@Component({
  components: {
    draggable
  }
})
export default class FireCalculator extends Vue {
  $refs!: {
    calculatorContainer: HTMLElement;
    calculateButton: HTMLElement;
  };
  
  plans: FirePlan[] = [];
  activePlanId: string = '';
  showAddPlanDialog: boolean = false;
  showEditPlanDialog: boolean = false;
  showSortDialog: boolean = false;
  newPlanName: string = '';
  editPlanName: string = '';
  editingPlanId: string = '';
  exporting: boolean = false;
  tempPlans: FirePlan[] = [];
  
  formData: FormData = {
    initialAssets: 2000000,
    startAge: 32,
    endAge: 60,
    annualReturn: 1.55
  };
  
  expenseItems: ExpenseItem[] = [
    { name: '总备用', amount: 200000, unit: 'yearly', duration: 1, untilEndAge: false },
    { name: '房贷', amount: 1075, unit: 'monthly', duration: 8, untilEndAge: false },
    { name: '每月', amount: 3000, unit: 'monthly', duration: 30, untilEndAge: true },
    { name: '年备用', amount: 10000, unit: 'yearly', duration: 30, untilEndAge: true },
    { name: '年孝顺', amount: 20000, unit: 'yearly', duration: 20, untilEndAge: false },
    { name: '年保险(养老、医疗)', amount: 5000, unit: 'yearly', duration: 30, untilEndAge: true },
    { name: '年人情', amount: 3000, unit: 'yearly', duration: 30, untilEndAge: true },
    { name: '年物业', amount: 1100, unit: 'yearly', duration: 30, untilEndAge: true },
    { name: '房子维修', amount: 10000, unit: 'yearly', duration: 1, untilEndAge: false },
    { name: '入户门和智能锁', amount: 6000, unit: 'yearly', duration: 1, untilEndAge: false },
    { name: '学厨', amount: 5000, unit: 'yearly', duration: 1, untilEndAge: false },
    { name: '游戏机和显示器', amount: 6000, unit: 'yearly', duration: 1, untilEndAge: false },
    { name: '电脑', amount: 10000, unit: 'yearly', duration: 1, untilEndAge: false },
    { name: '家电更新', amount: 10000, unit: 'yearly', duration: 1, untilEndAge: false }
  ];
  
  incomeItems: IncomeItem[] = [
    { name: '工资', amount: 0, unit: 'monthly', duration: 30, untilEndAge: true }
  ];
  
  result: ResultItem[] = [];
  sortOrder: 'asc' | 'desc' = 'desc';
  
  created() {
    this.loadFromStorage();
    this.checkUrlParams();
  }
  
  checkUrlParams() {
    const urlParams = new URLSearchParams(window.location.search);
    const dataParam = urlParams.get('data');
    
    if (dataParam === '1') {
      const savedData = localStorage.getItem(STORAGE_KEY);
      
      if (savedData) {
        try {
          const parsedData = JSON.parse(savedData);
          if (parsedData.plans && parsedData.plans.length > 0) {
            console.log('Using existing localStorage data, skipping default data import');
            return;
          }
        } catch (e) {
          console.error('Failed to parse localStorage data:', e);
        }
      }
      
      try {
        const data = defaultFireData as any;
        
        if (data.plans && data.plans.length > 0) {
          this.plans = data.plans.map((plan: any) => ({
            ...plan,
            formData: {
              initialAssets: Number(plan.formData.initialAssets) || 0,
              startAge: Number(plan.formData.startAge) || 32,
              endAge: Number(plan.formData.endAge) || 60,
              annualReturn: Number(plan.formData.annualReturn) || 1.55
            },
            expenseItems: (plan.expenseItems || []).map((item: any) => ({
              ...item,
              amount: Number(item.amount) || 0,
              duration: Number(item.duration) || 0
            })),
            incomeItems: (plan.incomeItems || []).map((item: any) => ({
              ...item,
              amount: Number(item.amount) || 0,
              duration: Number(item.duration) || 0
            }))
          }));
          
          if (data.activePlanId) {
            this.activePlanId = data.activePlanId;
          } else {
            this.activePlanId = this.plans[0].id;
          }
          
          const activePlan = this.plans.find(p => p.id === this.activePlanId);
          if (activePlan) {
            this.loadPlanData(activePlan);
          }
          
          this.saveToStorage();
          this.$toast.success(`已加载 ${this.plans.length} 个默认计划`);
        }
      } catch (error) {
        console.error('Failed to load default fire data:', error);
        this.$toast.fail('加载默认计划数据失败: ' + (error as Error).message);
      }
    }
  }
  
  get isFinancialFree(): boolean {
    if (this.result.length === 0) return false;
    const finalItem = this.result[this.result.length - 1];
    return finalItem.assets > 0;
  }
  
  get sortedResult() {
    return [...this.result].sort((a, b) => {
      if (this.sortOrder === 'asc') {
        return a.age - b.age;
      } else {
        return b.age - a.age;
      }
    });
  }
  
  get currentPlan(): FirePlan | undefined {
    return this.plans.find(p => p.id === this.activePlanId);
  }
  
  get totalYearlyExpense(): number {
    return this.expenseItems.reduce((total, item) => {
      if (item.untilEndAge || (!item.untilEndAge && Number(item.duration) > 0)) {
        if (item.unit === 'monthly') {
          return total + Number(item.amount) * 12;
        } else {
          return total + Number(item.amount);
        }
      }
      return total;
    }, 0);
  }
  
  get totalYearlyIncome(): number {
    return this.incomeItems.reduce((total, item) => {
      if (item.untilEndAge || (!item.untilEndAge && Number(item.duration) > 0)) {
        if (item.unit === 'monthly') {
          return total + Number(item.amount) * 12;
        } else {
          return total + Number(item.amount);
        }
      }
      return total;
    }, 0);
  }
  
  generateId(): string {
    return Date.now().toString(36) + Math.random().toString(36).substr(2);
  }
  
  createDefaultPlan(): FirePlan {
    return {
      id: this.generateId(),
      name: '默认计划',
      formData: {
        initialAssets: 1000000,
        startAge: 32,
        endAge: 60,
        annualReturn: 1.55
      },
      expenseItems: [
        { name: '年支出', amount: 50000, unit: 'yearly', duration: 30, untilEndAge: true }
      ],
      incomeItems: [
        { name: '年收入', amount: 10000, unit: 'yearly', duration: 30, untilEndAge: true }
      ],
      result: [],
      createdAt: Date.now()
    };
  }
  
  loadPlanData(plan: FirePlan) {
    this.formData = { ...plan.formData };
    this.expenseItems = JSON.parse(JSON.stringify(plan.expenseItems));
    this.incomeItems = JSON.parse(JSON.stringify(plan.incomeItems));
    this.result = plan.result && plan.result.length > 0 ? JSON.parse(JSON.stringify(plan.result)) : [];
  }
  
  saveCurrentPlan() {
    const index = this.plans.findIndex(p => p.id === this.activePlanId);
    if (index > -1) {
      const updatedPlan: FirePlan = {
        id: this.plans[index].id,
        name: this.plans[index].name,
        formData: { ...this.formData },
        expenseItems: JSON.parse(JSON.stringify(this.expenseItems)),
        incomeItems: JSON.parse(JSON.stringify(this.incomeItems)),
        result: JSON.parse(JSON.stringify(this.result)),
        createdAt: this.plans[index].createdAt
      };
      this.$set(this.plans, index, updatedPlan);
      this.saveToStorage();
    }
  }
  
  onPlanChange(planId: string) {
    // this.saveCurrentPlan();
    this.activePlanId = planId;
    const plan = this.plans.find(p => p.id === planId);
    if (plan) {
      this.loadPlanData(plan);
    }
  }
  
  openSortDialog() {
    this.tempPlans = JSON.parse(JSON.stringify(this.plans));
    this.showSortDialog = true;
  }
  
  confirmSort() {
    const newPlans = JSON.parse(JSON.stringify(this.tempPlans));
    this.plans.splice(0, this.plans.length, ...newPlans);
    this.saveToStorage();
    this.$toast.success('排序已保存');
  }
  
  cancelSort() {
    this.showSortDialog = false;
  }
  
  beforeAddPlanClose(action: string, done: () => void) {
    if (action === 'confirm') {
      if (!this.newPlanName.trim()) {
        this.$toast('请输入计划名称');
        return;
      }
      this.addNewPlan();
    }
    this.newPlanName = '';
    done();
  }
  
  openEditPlanDialog(plan: FirePlan | undefined) {
    if (!plan) return;
    this.editingPlanId = plan.id;
    this.editPlanName = plan.name;
    this.showEditPlanDialog = true;
  }
  
  beforeEditPlanClose(action: string, done: () => void) {
    if (action === 'confirm') {
      if (!this.editPlanName.trim()) {
        this.$toast('请输入计划名称');
        return;
      }
      this.updatePlanName();
    }
    this.editPlanName = '';
    this.editingPlanId = '';
    done();
  }
  
  updatePlanName() {
    const index = this.plans.findIndex(p => p.id === this.editingPlanId);
    if (index > -1) {
      const updatedPlan: FirePlan = JSON.parse(JSON.stringify(this.plans[index]));
      updatedPlan.name = this.editPlanName.trim();
      this.$set(this.plans, index, updatedPlan);
      this.saveToStorage();
      this.$toast.success('计划名称已更新');
    }
  }
  
  copyCurrentPlan() {
    const currentPlan = this.currentPlan;
    if (!currentPlan) {
      this.$toast('没有可复制的计划');
      return;
    }
    
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    const hours = String(now.getHours()).padStart(2, '0');
    const minutes = String(now.getMinutes()).padStart(2, '0');
    const seconds = String(now.getSeconds()).padStart(2, '0');
    const timestamp = `${year}${month}${day}${hours}${minutes}${seconds}`;
    
    const copiedPlan: FirePlan = JSON.parse(JSON.stringify(currentPlan));
    copiedPlan.id = this.generateId();
    copiedPlan.name = `${currentPlan.name}_副本${timestamp}`;
    copiedPlan.createdAt = Date.now();
    copiedPlan.result = [];
    
    this.plans.push(copiedPlan);
    this.activePlanId = copiedPlan.id;
    this.loadPlanData(copiedPlan);
    this.saveToStorage();
    this.$toast.success('计划已复制');
  }
  
  addNewPlan() {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    const planName = `${year}${month}${day}`;
    
    const newPlan = this.createDefaultPlan();
    newPlan.name = planName;
    
    this.plans.push(newPlan);
    this.activePlanId = newPlan.id;
    this.loadPlanData(newPlan);
    this.saveToStorage();
    this.$toast.success('计划创建成功');
  }
  
  confirmDeletePlan(planId: string) {
    this.$dialog.confirm({
      title: '删除计划',
      message: '确定要删除这个计划吗？删除后无法恢复。'
    }).then(() => {
      this.deletePlan(planId);
    }).catch(() => {});
  }
  
  confirmClearCache() {
    this.$dialog.confirm({
      title: '清除缓存',
      message: '确定要清除所有缓存数据吗？这将删除所有保存的计划数据，清除后无法恢复。'
    }).then(() => {
      this.clearCache();
    }).catch(() => {});
  }
  
  clearCache() {
    localStorage.removeItem(STORAGE_KEY);
    localStorage.removeItem('fire_calculator_data');
    this.plans = [];
    this.activePlanId = '';
    this.result = [];
    this.$toast.success('缓存已清除，页面将重新加载');
    setTimeout(() => {
      window.location.reload();
    }, 1000);
  }
  
  deletePlan(planId: string) {
    const index = this.plans.findIndex(p => p.id === planId);
    if (index > -1) {
      this.plans.splice(index, 1);
      if (this.activePlanId === planId && this.plans.length > 0) {
        this.activePlanId = this.plans[0].id;
        this.loadPlanData(this.plans[0]);
      }
      this.saveToStorage();
      this.$toast.success('计划已删除');
    }
  }
  
  async exportAsImage() {
    if (!this.$refs.calculatorContainer) {
      this.$toast.fail('导出失败');
      return;
    }
    
    this.exporting = true;
    
    await this.$nextTick();
    
    try {
      const scale = window.devicePixelRatio || 3;
      const canvas = await html2canvas(this.$refs.calculatorContainer, {
        backgroundColor: '#ffffff',
        scale: scale * 2,
        useCORS: true,
        logging: false,
        allowTaint: true,
        imageTimeout: 5000
      });
      
      const link = document.createElement('a');
      const plan = this.plans.find(p => p.id === this.activePlanId);
      const fileName = plan ? `${plan.name}_Fire计划.png` : 'Fire计划.png';
      
      link.download = fileName;
      link.href = canvas.toDataURL('image/png', 1.0);
      link.click();
      
      this.$toast.success('导出成功');
    } catch (error) {
      console.error('Export failed:', error);
      this.$toast.fail('导出失败');
    } finally {
      this.exporting = false;
    }
  }
  
  addExpenseItem() {
    this.expenseItems.push({ name: '', amount: 0, unit: 'yearly', duration: 30, untilEndAge: false });
  }
  
  removeExpenseItem(index: number) {
    this.expenseItems.splice(index, 1);
  }
  
  addIncomeItem() {
    this.incomeItems.push({ name: '', amount: 0, unit: 'yearly', duration: 30, untilEndAge: false });
  }
  
  removeIncomeItem(index: number) {
    this.incomeItems.splice(index, 1);
  }
  
  sortByAge() {
    this.sortOrder = this.sortOrder === 'asc' ? 'desc' : 'asc';
  }
  
  scrollToCalculate() {
    if (this.$refs.calculateButton) {
      this.$refs.calculateButton.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }
  
  scrollToTop() {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }
  
  saveToStorage() {
    const data = {
      plans: JSON.parse(JSON.stringify(this.plans)),
      activePlanId: this.activePlanId
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
  }
  
  loadFromStorage() {
    const savedData = localStorage.getItem(STORAGE_KEY);
    
    if (savedData) {
      try {
        const data = JSON.parse(savedData);
        if (data.plans && data.plans.length > 0) {
          this.plans = JSON.parse(JSON.stringify(data.plans));
          this.activePlanId = data.activePlanId || this.plans[0].id;
          const activePlan = this.plans.find(p => p.id === this.activePlanId);
          if (activePlan) {
            this.loadPlanData(activePlan);
          }
          return;
        }
      } catch (e) {
        console.error('Failed to load saved data:', e);
      }
    }
    
    const oldData = localStorage.getItem('fire_calculator_data');
    if (oldData) {
      try {
        const data = JSON.parse(oldData);
        const plan = this.createDefaultPlan();
        if (data.formData) {
          plan.formData = JSON.parse(JSON.stringify(data.formData));
        }
        if (data.expenseItems && data.expenseItems.length > 0) {
          plan.expenseItems = JSON.parse(JSON.stringify(data.expenseItems));
        }
        if (data.incomeItems && data.incomeItems.length > 0) {
          plan.incomeItems = JSON.parse(JSON.stringify(data.incomeItems));
        }
        this.plans = [plan];
        this.activePlanId = plan.id;
        this.loadPlanData(plan);
        this.calculate();
        localStorage.removeItem('fire_calculator_data');
        return;
      } catch (e) {
        console.error('Failed to migrate old data:', e);
      }
    }
    
    const defaultPlan = this.createDefaultPlan();
    this.plans = [defaultPlan];
    this.activePlanId = defaultPlan.id;
    this.loadPlanData(defaultPlan);
  }
  
  calculate() {
    this.result = [];
    const { initialAssets, startAge, endAge, annualReturn } = this.formData;
    
    const initialAssetsNum = Number(initialAssets);
    const startAgeNum = Number(startAge);
    const endAgeNum = Number(endAge);
    const annualReturnNum = Number(annualReturn);
    
    let currentAssets = initialAssetsNum;
    const currentYear = new Date().getFullYear();
    
    for (let i = 0; i <= endAgeNum - startAgeNum; i++) {
      const age = startAgeNum + i;
      const year = currentYear + i;
      
      let yearlyExpenseNum = 0;
      for (const expense of this.expenseItems) {
        const duration = Number(expense.duration);
        if (expense.untilEndAge || i < duration) {
          if (expense.unit === 'monthly') {
            yearlyExpenseNum += Number(expense.amount) * 12;
          } else {
            yearlyExpenseNum += Number(expense.amount);
          }
        }
      }
      
      let yearlyIncomeNum = 0;
      for (const income of this.incomeItems) {
        const duration = Number(income.duration);
        if (income.untilEndAge || i < duration) {
          if (income.unit === 'monthly') {
            yearlyIncomeNum += Number(income.amount) * 12;
          } else {
            yearlyIncomeNum += Number(income.amount);
          }
        }
      }
      
      const yearlyReturn = (currentAssets - yearlyExpenseNum) * (annualReturnNum / 100);
      
      currentAssets = currentAssets + yearlyReturn + yearlyIncomeNum - yearlyExpenseNum;
      
      this.result.push({
        year,
        age,
        assets: Math.max(0, currentAssets),
        yearlyExpense: yearlyExpenseNum,
        annualReturn: annualReturnNum,
        annualReturnAmount: yearlyReturn
      });
    }
    
    this.saveCurrentPlan();
  }
}
</script>

